import torch.nn as nn

# LLaVA-1.5 style: 2-layer MLP connector
class MLPConnector(nn.Module):
    def __init__(self, vision_hidden_size=1024, llm_hidden_size=4096):
        super().__init__()
        self.proj = nn.Sequential(
            nn.Linear(vision_hidden_size, llm_hidden_size),
            nn.GELU(),
            nn.Linear(llm_hidden_size, llm_hidden_size)
        )

    def forward(self, visual_tokens):
        # visual_tokens: (B, N, vision_hidden_size)
        return self.proj(visual_tokens)   # (B, N, llm_hidden_size)

# Q-Former style: compress N patch tokens to 32 query tokens
class QFormerConnector(nn.Module):
    def __init__(self, vision_dim=1024, llm_dim=4096, num_queries=32):
        super().__init__()
        self.queries = nn.Parameter(torch.zeros(1, num_queries, llm_dim))
        self.cross_attn = nn.MultiheadAttention(
            llm_dim, num_heads=16, batch_first=True
        )
        self.vision_proj = nn.Linear(vision_dim, llm_dim)

    def forward(self, patch_tokens):
        # patch_tokens: (B, N, vision_dim)
        keys = self.vision_proj(patch_tokens)              # (B, N, llm_dim)
        q = self.queries.expand(patch_tokens.size(0), -1, -1)  # (B, 32, llm_dim)
        out, _ = self.cross_attn(q, keys, keys)
        return out                                         # (B, 32, llm_dim)
